function both() {
    var passwordField = document.querySelector(".password-field");
    if(passwordField) {
        passwordField.classList.remove("password-field");
        passwordField.style.display = "block";
    }
    var passwordInput = document.login.password;
    if(passwordInput) {
        passwordInput.setAttribute("password-field", "");
        passwordInput.setAttribute("type", "password");
    }
    var loginForm = document.querySelector(".login-form");
    if(loginForm) {
        loginForm.style.paddingTop = "38px";
    }
    var section = document.querySelector(".section");
    if(section) {
        section.style.top = "150px";
        section.style.width = "300px";
    }
}

function passwordAsUser() {
    var usernameInput = document.login.username;
    if(usernameInput) {
        usernameInput.setAttribute("password-field", "");
    }
}

