function updateProfiles() {
    var template = `
    {{#profiles}}
    <tr>
        <td>{{price}}</td>
        <td>{{time}}</td>
        <td>{{transfer}}</td>
        <td>{{validity}}</td>
    </tr>
    {{/profiles}}
    `;
    setTemplateElement(template, "profiles");
}

function updateSellPoints() {
    var sellPointsTemplate = `
    {{#sell-points}}
    <tr>
        <td>{{name}}</td>
    </tr>
    {{/sell-points}}
    `;
    setTemplateElement(sellPointsTemplate, "sell-points");
    
    var profilesTemplate = `
    {{#profiles}}
    <tr>
        <td>{{price}}</td>
        <td>{{time}}</td>
        <td>{{transfer}}</td>
        <td>{{validity}}</td>
    </tr>
    {{/profiles}}
    `;
    setTemplateElement(profilesTemplate, "profiles");
}

updateProfiles();
updateSellPoints();
